print(normalize_telefono(' 999-000 ', digits_only=False))

def normalize_email(raw: str) -> str:
    """Pre: raw str. Post: strip+lower con @."""
    s = raw.strip().lower()
    if '@' not in s:
        raise ValueError('email sin @')
    return s
